import { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { LogOut, Menu, X, Store, Settings, Users, Package } from "lucide-react";
import { useAuth } from "@/contexts/AuthContext";

export default function AdminLayout({ children }) {
    const { logout } = useAuth();
    const navigate = useNavigate();
    const location = useLocation();
    const [sidebarOpen, setSidebarOpen] = useState(true);

    const menuItems = [
        { icon: Store, label: "Dashboard", path: "/admin/dashboard" },
        { icon: Package, label: "Products", path: "/admin/products" },
        { icon: Users, label: "Shops", path: "/admin/shops" },
        { icon: Settings, label: "Settings", path: "/admin/settings" },
    ];

    const handleLogout = () => {
        logout();
        navigate("/admin/login");
    };

    const isActive = (path) => location.pathname === path;

    return (
        <div className="min-h-screen bg-gray-50 flex">
            {/* Sidebar */}
            <div
                className={`fixed md:static top-0 left-0 h-screen bg-espresso text-ivory transition-transform duration-300 z-40 ${
                    sidebarOpen ? "w-64" : "w-20"
                } md:translate-x-0`}
            >
                {/* Logo */}
                <div className="p-6 border-b border-maroon">
                    <Link to="/" className="font-bold text-xl">
                        SLB
                    </Link>
                </div>

                {/* Menu */}
                <nav className="flex-1 py-6">
                    {menuItems.map((item) => {
                        const Icon = item.icon;
                        return (
                            <Link
                                key={item.path}
                                to={item.path}
                                className={`flex items-center gap-4 px-6 py-3 transition ${
                                    isActive(item.path)
                                        ? "bg-maroon border-r-4 border-maroon"
                                        : "hover:bg-opacity-80"
                                }`}
                            >
                                <Icon size={20} />
                                {sidebarOpen && <span>{item.label}</span>}
                            </Link>
                        );
                    })}
                </nav>

                {/* Logout */}
                <div className="p-6 border-t border-maroon">
                    <button
                        onClick={handleLogout}
                        className="flex items-center gap-4 w-full px-4 py-2 rounded bg-maroon hover:bg-maroon/80 transition"
                    >
                        <LogOut size={20} />
                        {sidebarOpen && <span>Logout</span>}
                    </button>
                </div>
            </div>

            {/* Main Content */}
            <div className="flex-1">
                {/* Mobile Header */}
                <div className="md:hidden bg-white border-b border-line-soft sticky top-0 z-30">
                    <div className="flex items-center justify-between p-4">
                        <h1 className="font-bold text-lg">Admin</h1>
                        <button
                            onClick={() => setSidebarOpen(!sidebarOpen)}
                            className="p-2 hover:bg-gray-100 rounded"
                        >
                            {sidebarOpen ? <X size={24} /> : <Menu size={24} />}
                        </button>
                    </div>
                </div>

                {/* Page Content */}
                <main className="p-6 md:p-8">
                    {children}
                </main>
            </div>
        </div>
    );
}
